import { db } from './db';

export class UserService {
  async getUser(id: string) {
    const user = await db.findById(id);
    return user;
  }

  async createUser(name: string, email: string) {
    const user = await db.create({ name, email });
    return user;
  }

  async deleteUser(id: string) {
    await db.delete(id);
  }
}

